const { initialInvestmentCost, projectLifespan, averageAnnualDamageBeforeResilience, reductionInDamagePercentage, averageAnnualOperationalSavings, averageAnnualCoBenefits, discountRate } = inputs;

const dr = discountRate / 100; // Convert percentage to decimal

// Input validation and edge cases
if (initialInvestmentCost < 0 || projectLifespan <= 0 || dr < 0) {
    return {
        totalBenefits: 0,
        netPresentValue: 0,
        returnOnInvestment: 0,
        paybackPeriod: 0
    };
}

const annualAvoidedLosses = averageAnnualDamageBeforeResilience * (reductionInDamagePercentage / 100);
const totalAnnualBenefits = annualAvoidedLosses + averageAnnualOperationalSavings + averageAnnualCoBenefits;

let netPresentValue = -initialInvestmentCost;
let totalUndiscountedBenefits = 0;

for (let t = 1; t <= projectLifespan; t++) {
    const discountedAnnualBenefit = totalAnnualBenefits / Math.pow((1 + dr), t);
    netPresentValue += discountedAnnualBenefit;
    totalUndiscountedBenefits += totalAnnualBenefits; // Accumulate for total benefits over lifespan
}

let returnOnInvestment = 0;
if (initialInvestmentCost > 0) {
    returnOnInvestment = ((totalUndiscountedBenefits - initialInvestmentCost) / initialInvestmentCost) * 100;
} else if (totalUndiscountedBenefits > 0) {
    returnOnInvestment = Infinity; // Infinite ROI if cost is zero and benefits exist
}

let paybackPeriod;
if (initialInvestmentCost <= 0) {
    paybackPeriod = 0; // No cost, immediate payback
} else if (totalAnnualBenefits <= 0) {
    paybackPeriod = Infinity; // Will never pay back if no annual benefits
} else {
    paybackPeriod = initialInvestmentCost / totalAnnualBenefits;
    if (paybackPeriod > projectLifespan) {
        paybackPeriod = projectLifespan + 0.99; // Indicate beyond lifespan for display purposes without being actual infinity
    }
}

return {
    totalBenefits: isFinite(totalUndiscountedBenefits) ? totalUndiscountedBenefits : 0,
    netPresentValue: isFinite(netPresentValue) ? netPresentValue : 0,
    returnOnInvestment: isFinite(returnOnInvestment) ? returnOnInvestment : 0,
    paybackPeriod: isFinite(paybackPeriod) ? paybackPeriod : 0
};
